/** @format */

import React from "react";
import "./skills.css";
import MachineLearning from "./MachineLearning";
import DataAnalysis from "./DataAnalysis";
import Webdevelopment from "./Webdevelopment";
import Frontend from "./Frontend";
import Backend from "./Backend";
import Slider from "react-slick"; // Import React Slick

const Skills = () => {
	// Slick slider settings
	const settings = {
		dots: true,
		infinite: true,
		speed: 500,
		slidesToShow: 3, // Number of visible slides
		slidesToScroll: 1,
		centerMode: true, // Center the slides to make them aligned
		centerPadding: "20px", // Control the padding between the slides
		responsive: [
			{
				breakpoint: 1024,
				settings: {
					slidesToShow: 2,
					slidesToScroll: 1,
					centerMode: true,
				},
			},
			{
				breakpoint: 600,
				settings: {
					slidesToShow: 1,
					slidesToScroll: 1,
					centerMode: false,
				},
			},
		],
	};

	return (
		<section className="skills section" id="skills">
			<h2 className="section__title">Skills</h2>
			<span className="section__subtitle">My technical level</span>

			<Slider {...settings}>
				<div>
					<Webdevelopment />
				</div>
				<div>
					<DataAnalysis />
				</div>
				<div>
					<MachineLearning />
				</div>
				<div>
					<Frontend />
				</div>
				<div>
					<Backend />
				</div>
			</Slider>
		</section>
	);
};

export default Skills;
